"""
generate_reports.py

Generates benchmark and correlation reports from analysis results.
Specifically updates benchmark_report.md to include raw energy metrics, MAE CI,
scaling factor, CI, and hypothesis test result.
"""
import os
import json
from pathlib import Path
from typing import Optional, Dict, Any
import pandas as pd

from logger import get_logger, info, warning, error
from analyze_energies import calculate_metrics, bootstrap_analysis

logger = get_logger(__name__)

def load_energies_csv(csv_path: str) -> pd.DataFrame:
    """Load the raw energies CSV generated by analyze_energies.py."""
    path = Path(csv_path)
    if not path.exists():
        raise FileNotFoundError(f"Energy CSV not found at {csv_path}")
    return pd.read_csv(csv_path)

def load_statistics_json(json_path: str) -> Dict[str, Any]:
    """Load the statistics JSON generated by analyze_energies.py."""
    path = Path(json_path)
    if not path.exists():
        raise FileNotFoundError(f"Statistics JSON not found at {json_path}")
    with open(path, 'r') as f:
        return json.load(f)

def load_scaling_results(json_path: str) -> Dict[str, Any]:
    """Load the scaling results JSON generated by derive_scaling.py."""
    path = Path(json_path)
    if not path.exists():
        raise FileNotFoundError(f"Scaling results JSON not found at {json_path}")
    with open(path, 'r') as f:
        return json.load(f)

def generate_benchmark_report(
    energies_csv: str,
    stats_json: str,
    scaling_json: str,
    output_path: str
) -> None:
    """
    Generate benchmark_report.md including raw energy metrics, MAE CI,
    scaling factor, CI, and hypothesis test result.

    Reads raw_energies.csv, stats.json (containing bootstrap results),
    and scaling_results.json to populate the report.
    """
    logger.info(f"Generating benchmark report from {energies_csv}, {stats_json}, and {scaling_json}")

    try:
        df = load_energies_csv(energies_csv)
        stats = load_statistics_json(stats_json)
        scaling = load_scaling_results(scaling_json)
    except Exception as e:
        error(f"Failed to load data for report generation: {e}")
        raise

    # Extract metrics from stats
    raw_mae = stats.get('raw_mae', 0.0)
    raw_rmse = stats.get('raw_rmse', 0.0)
    raw_mse = stats.get('raw_mse', 0.0)
    raw_msd = stats.get('raw_msd', 0.0) # Mean Signed Error / Bias

    # Extract Bootstrap CI for MAE
    mae_ci = stats.get('mae_ci_95', {'lower': 0.0, 'upper': 0.0})
    mae_ci_lower = mae_ci.get('lower', 0.0)
    mae_ci_upper = mae_ci.get('upper', 0.0)

    # Extract Scaling Results
    optimal_s = scaling.get('optimal_s', 1.0)
    s_ci = scaling.get('ci_95', {'lower': 1.0, 'upper': 1.0})
    s_ci_lower = s_ci.get('lower', 1.0)
    s_ci_upper = s_ci.get('upper', 1.0)
    
    # Hypothesis test result: Does CI exclude 1.0?
    excludes_one = not (s_ci_lower <= 1.0 <= s_ci_upper)
    hypothesis_result = "Significant" if excludes_one else "Not Significant"
    hypothesis_text = (
        f"The 95% CI for the scaling factor ({s_ci_lower:.4f} to {s_ci_upper:.4f}) "
        f"{'excludes' if excludes_one else 'includes'} 1.0. "
        f"Thus, the optimal scaling factor is {'significantly' if excludes_one else 'not significantly'} different from 1.0."
    )

    # Count ion pairs
    n_pairs = len(df)

    # Construct report content
    report_lines = [
        "# DFT-D3 Benchmark Report for Ionic Liquids",
        "",
        "## Summary",
        "",
        f"This report summarizes the benchmarking of DFT-D3 dispersion corrections",
        f"against high-level CCSD(T)/CBS reference interaction energies for {n_pairs} ion pairs.",
        "",
        "## Raw Energy Metrics",
        "",
        "| Metric | Value (kcal/mol) |",
        "|---|---|",
        f"| Mean Absolute Error (MAE) | {raw_mae:.4f} |",
        f"| Root Mean Square Error (RMSE) | {raw_rmse:.4f} |",
        f"| Mean Squared Error (MSE) | {raw_mse:.4f} |",
        f"| Mean Signed Error (Bias) | {raw_msd:.4f} |",
        "",
        "## Statistical Confidence (Bootstrap)",
        "",
        "95% Confidence Interval for MAE (1,000 replicates):",
        f"- **Lower Bound**: {mae_ci_lower:.4f} kcal/mol",
        f"- **Upper Bound**: {mae_ci_upper:.4f} kcal/mol",
        "",
        "## Scaling Correction Analysis",
        "",
        "A linear scaling factor `s` was derived to minimize the MAE of the corrected energies (E_corrected = E_base + s * E_D3).",
        "",
        f"- **Optimal Scaling Factor (s)**: {optimal_s:.4f}",
        "",
        "95% Confidence Interval for `s` (1,000 replicates):",
        f"- **Lower Bound**: {s_ci_lower:.4f}",
        f"- **Upper Bound**: {s_ci_upper:.4f}",
        "",
        "### Hypothesis Test (H0: s = 1.0)",
        "",
        hypothesis_text,
        "",
        "## Data Overview",
        "",
        "The analysis is based on the following dataset:",
        f"- Source: `data/IL-Benchmark-local.zip` (Synthetic Fallback)",
        f"- Size: {n_pairs} ion pairs",
        "",
        "### Raw Energy Table",
        "",
        "The table below lists the reference and computed energies for each pair.",
        "",
        "| Pair ID | Reference (kcal/mol) | DFT Total (kcal/mol) | D3 Term (kcal/mol) | Signed Error (kcal/mol) |",
        "|---|---|---|---|---|",
    ]

    # Append rows
    for _, row in df.iterrows():
        pair_id = row['pair_id']
        ref = row['reference_energy']
        dft = row['dft_total_energy']
        d3 = row['d3_dispersion_energy']
        err = row['signed_error']
        report_lines.append(
            f"| {pair_id} | {ref:.4f} | {dft:.4f} | {d3:.4f} | {err:.4f} |"
        )

    report_content = "\n".join(report_lines)

    # Write file
    output_file = Path(output_path)
    output_file.parent.mkdir(parents=True, exist_ok=True)
    with open(output_file, 'w') as f:
        f.write(report_content)

    info(f"Benchmark report successfully written to {output_path}")

def main():
    """Main entry point for report generation."""
    # Define paths relative to project root
    project_root = Path(__file__).resolve().parent.parent
    data_dir = project_root / "data"
    derived_dir = project_root / "data" / "derived"
    
    # Ensure derived directory exists
    derived_dir.mkdir(parents=True, exist_ok=True)

    energies_csv = derived_dir / "raw_energies.csv"
    stats_json = derived_dir / "stats.json"
    scaling_json = derived_dir / "scaling_results.json"
    report_md = derived_dir / "benchmark_report.md"

    if not energies_csv.exists():
        error(f"Required input file missing: {energies_csv}")
        error("Please run code/analyze_energies.py first to generate raw_energies.csv and stats.json.")
        return 1

    if not stats_json.exists():
        error(f"Required input file missing: {stats_json}")
        error("Please run code/analyze_energies.py first to generate stats.json.")
        return 1

    if not scaling_json.exists():
        error(f"Required input file missing: {scaling_json}")
        error("Please run code/derive_scaling.py first to generate scaling_results.json.")
        return 1

    try:
        generate_benchmark_report(
            str(energies_csv),
            str(stats_json),
            str(scaling_json),
            str(report_md)
        )
        return 0
    except Exception as e:
        error(f"Report generation failed: {e}")
        return 1

if __name__ == "__main__":
    exit(main())